<!DOCTYPE html>
<html>
<head>
  <title>Billiards Game</title>
  <style>
    body {
      margin: 0;
      padding: 20px;
      display: flex;
      flex-direction: column;
      align-items: center;
      background: #1a1a1a;
      font-family: Arial, sans-serif;
      color: white;
    }
    canvas {
      background: #2d5016;
      border: 15px solid #8B4513;
      display: block;
      margin: 20px 0;
      cursor: crosshair;
      box-shadow: 0 0 20px rgba(0,0,0,0.8);
    }
    .controls {
      display: flex;
      gap: 10px;
      margin-bottom: 20px;
    }
    button {
      padding: 10px 20px;
      font-size: 14px;
      background: #4CAF50;
      color: white;
      border: none;
      border-radius: 4px;
      cursor: pointer;
      transition: background 0.2s;
    }
    button:hover {
      background: #45a049;
    }
    .instructions {
      max-width: 700px;
      font-size: 14px;
      line-height: 1.6;
      background: #333;
      padding: 15px;
      border-radius: 4px;
      margin-bottom: 20px;
      border-left: 4px solid #4CAF50;
    }
    h1 {
      margin: 0 0 10px 0;
    }
  </style>
</head>
<body>
  <h1>Billiards Game</h1>

  <div class="instructions">
    <strong>How to Play:</strong><br>
    • Click and drag the <strong>white cue ball BACKWARD</strong> (away from table center) to aim and set power<br>
    • The further back you drag, the harder the shot<br>
    • Release to shoot<br>
    • Click "Reset" to rack the balls again
  </div>

  <div class="controls">
    <button id="resetBtn">Reset / Rack</button>
    <button id="pauseBtn">Pause</button>
  </div>

  <canvas id="gameCanvas"></canvas>

  <script>
    const canvas = document.getElementById('gameCanvas');
    const ctx = canvas.getContext('2d');

    const WIDTH = 1200;
    const HEIGHT = 600;
    canvas.width = WIDTH;
    canvas.height = HEIGHT;

    const BALL_RADIUS = 8;
    const FRICTION_COEFFICIENT = 4.5; // for exponential decay
    const MAX_SPEED = 500;
    const COLLISION_DAMPING = 0.99;
    const STOP_THRESHOLD = 0.15;

    const POCKET_POSITIONS = [
      { x: 18, y: 18 },
      { x: WIDTH - 18, y: 18 },
      { x: WIDTH / 2, y: 12 },
      { x: 18, y: HEIGHT - 18 },
      { x: WIDTH - 18, y: HEIGHT - 18 },
      { x: WIDTH / 2, y: HEIGHT - 12 }
    ];
    const POCKET_RADIUS = 15;

    class Ball {
      constructor(x, y, vx = 0, vy = 0, cue = false) {
        this.x = x;
        this.y = y;
        this.vx = vx;
        this.vy = vy;
        this.cue = cue;
        this.potted = false;
      }

      update(dt) {
        if (this.potted) return;

        // Apply friction (exponential decay)
        const damping = Math.exp(-FRICTION_COEFFICIENT * dt);
        this.vx *= damping;
        this.vy *= damping;

        // Stop if very slow
        let speed = Math.sqrt(this.vx * this.vx + this.vy * this.vy);
        if (speed < STOP_THRESHOLD) {
          this.vx = 0;
          this.vy = 0;
          return;
        }

        // Update position
        this.x += this.vx * dt;
        this.y += this.vy * dt;

        // Wall collisions
        if (this.x - BALL_RADIUS < 0) {
          this.x = BALL_RADIUS;
          this.vx = Math.abs(this.vx) * COLLISION_DAMPING;
        }
        if (this.x + BALL_RADIUS > WIDTH) {
          this.x = WIDTH - BALL_RADIUS;
          this.vx = -Math.abs(this.vx) * COLLISION_DAMPING;
        }
        if (this.y - BALL_RADIUS < 0) {
          this.y = BALL_RADIUS;
          this.vy = Math.abs(this.vy) * COLLISION_DAMPING;
        }
        if (this.y + BALL_RADIUS > HEIGHT) {
          this.y = HEIGHT - BALL_RADIUS;
          this.vy = -Math.abs(this.vy) * COLLISION_DAMPING;
        }

        // Check pockets
        for (let pocket of POCKET_POSITIONS) {
          let dx = this.x - pocket.x;
          let dy = this.y - pocket.y;
          let dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < POCKET_RADIUS) {
            this.potted = true;
            this.vx = 0;
            this.vy = 0;
            return;
          }
        }
      }

      draw() {
        if (this.potted) return;

        ctx.fillStyle = this.cue ? '#ffffff' : '#ff1111';
        ctx.beginPath();
        ctx.arc(this.x, this.y, BALL_RADIUS, 0, Math.PI * 2);
        ctx.fill();

        ctx.strokeStyle = '#000';
        ctx.lineWidth = 0.5;
        ctx.stroke();
      }
    }

    class SimEngine {
      constructor() {
        this.W = WIDTH;
        this.H = HEIGHT;
        this.R = BALL_RADIUS;
        this.balls = [];
        this.animationId = null;
        this.paused = false;
        this.lastTime = Date.now();
      }

      reset(ballsData) {
        this.balls = ballsData.map(b => new Ball(b.x, b.y, b.vx || 0, b.vy || 0, b.cue || false));
      }

      step(dt) {
        // Limit dt for numerical stability
        dt = Math.min(dt, 0.016);

        // Update each ball
        for (let ball of this.balls) {
          ball.update(dt);
        }

        // Ball-to-ball collision detection and response
        for (let i = 0; i < this.balls.length; i++) {
          for (let j = i + 1; j < this.balls.length; j++) {
            let b1 = this.balls[i];
            let b2 = this.balls[j];

            if (b1.potted || b2.potted) continue;

            let dx = b2.x - b1.x;
            let dy = b2.y - b1.y;
            let dist = Math.sqrt(dx * dx + dy * dy);

            const MIN_DIST = BALL_RADIUS * 2 - 0.01;
            if (dist < MIN_DIST && dist > 0.01) {
              // Normalize collision normal
              let nx = dx / dist;
              let ny = dy / dist;

              // Relative velocity
              let dvx = b2.vx - b1.vx;
              let dvy = b2.vy - b1.vy;

              // Relative velocity along normal
              let dvn = dvx * nx + dvy * ny;

              // Only collide if moving toward each other
              if (dvn < 0) {
                // Equal mass elastic collision
                b1.vx += dvn * nx * COLLISION_DAMPING;
                b1.vy += dvn * ny * COLLISION_DAMPING;
                b2.vx -= dvn * nx * COLLISION_DAMPING;
                b2.vy -= dvn * ny * COLLISION_DAMPING;

                // Separate to prevent overlap
                let overlap = MIN_DIST - dist;
                let sep = overlap / 2 + 0.5;
                b1.x -= sep * nx;
                b1.y -= sep * ny;
                b2.x += sep * nx;
                b2.y += sep * ny;
              }
            }
          }
        }

        this.draw();
      }

      state() {
        return this.balls.map(b => ({
          x: b.x,
          y: b.y,
          vx: b.vx,
          vy: b.vy,
          potted: b.potted,
          cue: b.cue
        }));
      }

      shoot(vx, vy) {
        let cueBall = this.balls.find(b => b.cue);
        if (cueBall && !cueBall.potted) {
          cueBall.vx = vx;
          cueBall.vy = vy;
        }
      }

      pause() {
        this.paused = true;
      }

      resume() {
        this.paused = false;
      }

      draw() {
        // Clear with felt color
        ctx.fillStyle = '#2d5016';
        ctx.fillRect(0, 0, WIDTH, HEIGHT);

        // Draw rails/cushions
        ctx.fillStyle = '#1a3a0a';
        ctx.fillRect(0, 0, WIDTH, 15);
        ctx.fillRect(0, HEIGHT - 15, WIDTH, 15);
        ctx.fillRect(0, 0, 15, HEIGHT);
        ctx.fillRect(WIDTH - 15, 0, 15, HEIGHT);

        // Draw pockets
        ctx.fillStyle = '#000';
        for (let p of POCKET_POSITIONS) {
          ctx.beginPath();
          ctx.arc(p.x, p.y, POCKET_RADIUS, 0, Math.PI * 2);
          ctx.fill();
        }

        // Draw balls
        for (let ball of this.balls) {
          ball.draw();
        }
      }

      start() {
        const animate = () => {
          if (!this.paused) {
            let now = Date.now();
            let dt = (now - this.lastTime) / 1000;
            this.lastTime = now;
            this.step(dt);
          }
          this.animationId = requestAnimationFrame(animate);
        };
        animate();
      }

      stop() {
        if (this.animationId) {
          cancelAnimationFrame(this.animationId);
        }
      }
    }

    const sim = new SimEngine();
    window.sim = sim;

    function setupDefaultRack() {
      const ballsData = [
        { x: 100, y: HEIGHT / 2, cue: true }
      ];

      const startX = WIDTH - 250;
      const startY = HEIGHT / 2;
      const spacing = BALL_RADIUS * 2.8;

      for (let row = 0; row < 4; row++) {
        for (let col = 0; col <= row; col++) {
          const x = startX + row * spacing * 0.866;
          const y = startY - (row * spacing / 2) + (col * spacing);
          ballsData.push({ x, y, vx: 0, vy: 0 });
        }
      }

      sim.reset(ballsData);
      sim.draw();
    }

    setupDefaultRack();

    let isDragging = false;
    let dragStartX, dragStartY;
    let dragCueBall = null;

    canvas.addEventListener('mousedown', (e) => {
      const rect = canvas.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;

      dragCueBall = sim.balls.find(b => b.cue && !b.potted);
      if (dragCueBall) {
        let dx = x - dragCueBall.x;
        let dy = y - dragCueBall.y;
        let dist = Math.sqrt(dx * dx + dy * dy);
        if (dist < BALL_RADIUS * 4) {
          isDragging = true;
          dragStartX = x;
          dragStartY = y;
        }
      }
    });

    canvas.addEventListener('mousemove', (e) => {
      if (!isDragging || !dragCueBall) return;

      const rect = canvas.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;

      sim.draw();

      // Draw aim line
      ctx.strokeStyle = 'rgba(255, 255, 0, 0.7)';
      ctx.lineWidth = 2;
      ctx.setLineDash([5, 5]);
      ctx.beginPath();
      ctx.moveTo(dragCueBall.x, dragCueBall.y);
      ctx.lineTo(x, y);
      ctx.stroke();
      ctx.setLineDash([]);

      // Draw power bar
      const dragDist = Math.sqrt((x - dragStartX) ** 2 + (y - dragStartY) ** 2);
      const powerWidth = Math.min(dragDist * 1.5, 150);
      ctx.fillStyle = 'rgba(255, 200, 0, 0.5)';
      ctx.fillRect(10, 10, powerWidth, 12);
      ctx.strokeStyle = 'rgba(255, 200, 0, 0.8)';
      ctx.lineWidth = 1;
      ctx.strokeRect(10, 10, 150, 12);
    });

    canvas.addEventListener('mouseup', (e) => {
      if (!isDragging || !dragCueBall) return;

      const rect = canvas.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;

      let vx = (dragStartX - x) * 2.2;
      let vy = (dragStartY - y) * 2.2;

      let speed = Math.sqrt(vx * vx + vy * vy);
      if (speed > MAX_SPEED) {
        const scale = MAX_SPEED / speed;
        vx *= scale;
        vy *= scale;
      }

      sim.shoot(vx, vy);
      isDragging = false;
      dragCueBall = null;
    });

    document.getElementById('resetBtn').addEventListener('click', () => {
      setupDefaultRack();
    });

    document.getElementById('pauseBtn').addEventListener('click', (e) => {
      if (sim.paused) {
        sim.resume();
        e.target.textContent = 'Pause';
      } else {
        sim.pause();
        e.target.textContent = 'Resume';
      }
    });

    sim.start();
  </script>
</body>
</html>
